payload.raw:
{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第1–2月",
      "title": "材料与硬件攻坚",
      "description": "完成仿生柔性传感器微结构设计、液态金属-聚氨酯复合材料制备及信号标定，构建0.1mm级空间分辨率的混合传感架构。"
    },
    {
      "date": "第3月",
      "title": "算法开发与融合",
      "description": "训练高鲁棒手势识别分层模型（CNN-LSTM融合架构），开发多模态统一时空对齐协议，实现毫秒级实时推理与跨设备部署效率提升60%。"
    },
    {
      "date": "第4月",
      "title": "系统集成闭环",
      "description": "软硬件联调，嵌入微型电磁致动器阵列与半导体温控模块，构建感知-意图-反馈闭环，支持压力/温度微秒级精准调控。"
    },
    {
      "date": "第5–6月",
      "title": "多场景验证优化",
      "description": "依托H-Box全息舱、李未可眼镜等平台，在工业远程操控与虚拟实训场景开展压力测试，迭代用户体验并形成可复用交互标准接口。"
    }
  ]
}

